-- Seed Lincoln Township municipal documents (idempotent)
INSERT INTO public.municipal_documents (
  region_id, slug, kind, title, subtitle, description,
  adopted_date, adopted_by, pdf_url, pdf_size_label,
  meta, sections, table_of_contents, display_order, status, published_at
) VALUES
  ((SELECT id FROM public.regions WHERE slug = 'lincoln-township'), 'master-plan-2040', 'master_plan', 'Master Plan 2040', 'Lincoln Township', 'The Master Plan establishes a framework for Lincoln Township''s future development, balancing growth with preservation of the Township''s rural character, natural resources, and ecological balance. It covers land use, housing, economy, transportation, and community services.', 'March 12, 2024', 'the Planning Commission', 'https://kifhbevwmpqdeuxqnjxa.supabase.co/storage/v1/object/public/media/municipal-documents/master-plan-2040.pdf', '11.3', '[{"label":"Population (2020 Census)","value":"1,805 residents","icon":"people"},{"label":"Total Area","value":"22,967 acres (35.9 sq mi)","icon":"landscape"},{"label":"Median Age","value":"56.3 years","icon":"person"},{"label":"Housing Units","value":"86.2% single-family, 56.2% vacant/seasonal","icon":"home"},{"label":"Median Home Value","value":"$115,027","icon":"attach-money"},{"label":"Largest Lake","value":"Lake George (134 acres)","icon":"water"},{"label":"Woodland Coverage","value":"82.5% of Township","icon":"park"},{"label":"Major Employers","value":"Manufacturing (14.7%), Healthcare (15.3%), Retail (11.5%)","icon":"business"}]'::jsonb, '[{"title":"Community-Wide Goals","items":["Preserve and protect abundant natural resources including woodlands, lakes, and wetlands","Bolster public awareness and citizen participation in local planning","Manage new growth to retain the rural character of the community","Preserve property owners'' rights while maintaining community aesthetics","Relate land use to natural characteristics and long-term community needs","Encourage intergovernmental cooperation with Clare County and the State","Alleviate blight to present a better image of the Township"]},{"title":"Future Land Use Categories","items":["Rural Residential — 66.7% of land area (15,331 acres)","Single-Family Residential — 5.2% (1,206 acres)","Residential Recreation — 7.6% (1,741 acres)","Multi-Family Residential — designated near Lake George","Central Business District and Commercial zones","Industrial — 0.9% (209 acres)","Property Owned by Gas Companies — 15.0% (3,441 acres)","Recreation and State Land areas"]},{"title":"Key Services & Infrastructure","items":["Police: Clare County Sheriff''s Department (7 days/week patrols)","Fire: Lincoln Township volunteer fire department (also serves Freeman Twp)","Utilities: Consumers Energy & Great Lakes Energy (electric), DTE Gas (natural gas)","Water/Sewer: Private wells and septic systems (no public systems)","Transit: Clare County Transit Corporation (CCTC)","Waste: Green For Life (GFL) curbside trash and recycling","Schools: Farwell Area School District (4 schools, 989 students)","Senior Center at Township Hall with meals, activities, emergency services"]}]'::jsonb, '["Introduction","Executive Summary","Socioeconomic Profile","Natural Resources Assessment","Existing Land Use Analysis","Community Facilities and Services","Community Goals and Objectives","Future Land Use Plan","Plan Implementation Resources"]'::jsonb, 10, 'published', now()),
  ((SELECT id FROM public.regions WHERE slug = 'lincoln-township'), 'recreation-plan-2026-2030', 'recreation_plan', 'Recreation Plan 2026–2030', 'Lincoln Township', 'This five-year recreation plan guides future parks and recreation improvements for Lincoln Township. It makes the Township eligible for grant funding from the Michigan Department of Natural Resources (MDNR) through calendar year 2030.', 'January 12, 2026', 'the Board of Trustees', 'https://kifhbevwmpqdeuxqnjxa.supabase.co/storage/v1/object/public/media/municipal-documents/recreation-plan-2026-2030.pdf', '4.2', '[{"label":"Plan Period","value":"2026–2030 (5 years)","icon":"date-range"},{"label":"Township Parks","value":"Bertha Park, Shingle Lake Park, Silver Lake Park","icon":"park"},{"label":"Total Parkland","value":"26.1 acres (Hamlin Field accounts for 20 acres)","icon":"terrain"},{"label":"Parks Budget (2025)","value":"$77,434","icon":"account-balance"},{"label":"School District","value":"Farwell Area School District (4 schools)","icon":"school"},{"label":"Key Gap","value":"No community parks, sports parks, or non-motorized trails","icon":"warning"}]'::jsonb, '[{"title":"Recreation Goals","items":["Promote healthy lifestyles and active play for everyone regardless of age or socioeconomic status","Provide safe, accessible, and inclusive public parks and recreation facilities","Maintain existing facilities and support new non-motorized trails for mobility and healthy living","Implement recommendations cost effectively with creative funding strategies"]},{"title":"Recommended Trail Projects","items":["Shared Use Pathway: Lake George to White Birch Campground (~7 miles, highest priority)","Pedestrian/Bicycle Travel enhancements: crossings, signage, bike racks, benches, trailheads","Shared Use Pathway: Lake George to western Township border (~1.5 miles)","Shared Use Pathway: White Birch Lakes to southern border (~1 mile)"]},{"title":"Park Facility Needs (based on NRPA guidelines)","items":["Community Parks: 11.7 acres needed, 0 existing (deficit of -11.7)","Sports Parks: 40 acres recommended, 0 existing (deficit of -40)","Neighborhood Parks: 3.2 acres recommended, 23 acres existing (surplus of +19.8)","Non-Motorized Trails: 0 existing; NRPA recommends 2–9.2 miles for the population","Rectangular fields and driving ranges: each showing -1 deficit"]},{"title":"Community Organizations","items":["Friends of Clare County Parks and Recreation (non-profit, grants and events)","Lake George Property Owners Association (5K run, parades, car show)","White Birch Lakes Recreational Association","Clare Little League, Pony League, Youth & Rocket Football, Adult Softball","Unicorn Garden Club","Lake George Booster''s Club"]}]'::jsonb, '["Introduction & Community Description","Administrative Structure","Recreation Inventory","Planning & Public Input Process","Recreation Needs Analysis","Action Program"]'::jsonb, 20, 'published', now()),
  ((SELECT id FROM public.regions WHERE slug = 'lincoln-township'), 'zoning-ordinance-44', 'zoning_ordinance', 'Zoning Ordinance', 'Ordinance No. 44', 'The Zoning Ordinance regulates land use and development across Lincoln Township. It establishes zoning districts, permitted uses, site development requirements, and standards for structures, parking, landscaping, environmental protection, and signs. Last amended April 1, 2022.', 'August 14, 2017', 'the Lincoln Township Board', 'https://kifhbevwmpqdeuxqnjxa.supabase.co/storage/v1/object/public/media/municipal-documents/zoning-ordinance-44.pdf', '2.0', '[{"label":"Ordinance Number","value":"No. 44","icon":"gavel"},{"label":"Effective Date","value":"September 1, 2017","icon":"event"},{"label":"Last Amended","value":"April 1, 2022","icon":"update"},{"label":"Zoning Administrator","value":"Dick Hassberger","icon":"person"},{"label":"Permit Required","value":"Yes — for most grading, construction, and use changes","icon":"assignment"},{"label":"First Offense Penalty","value":"$100 civil infraction","icon":"report"}]'::jsonb, '[{"title":"Zoning Districts","items":["Residential, commercial, and industrial district classifications","Planned Unit Development (PUD) district for mixed-use projects","Site development requirements for each district (setbacks, lot size, density)","Special district provisions and voting place exception"]},{"title":"Permit Process","items":["Zoning permits required before grading, excavation, or construction","Single-family/two-family: Zoning Administrator approval within 15 days","Other uses: Planning Commission review required (90-day timeline)","Special Land Uses require Planning Commission final action","Variances handled by the Zoning Board of Appeals (ZBA)","Pre-application meetings available before formal submission"]},{"title":"Key Regulations","items":["Off-street parking and loading requirements by use type","Landscaping and screening standards with buffer zones","Environmental protection: natural resources, stormwater, emissions, shorelines","Access and private road standards with clear vision zones","Sign standards and regulations by district","Nonconforming lots, structures, and uses provisions"]},{"title":"Special Land Use Standards","items":["Airports, bed & breakfasts, campgrounds, commercial stables","Child/adult care facilities, extraction operations","Golf courses, hospitals, kennels, mini storage","Motels/hotels, multi-family developments","Solar energy systems, wind energy turbines","Wireless communication facilities, vehicle repair shops","Medical marihuana, shooting ranges, site condominiums","Common use lakefront lots, outdoor furnaces"]}]'::jsonb, '["Title and Purpose","General Administration, Enforcement, and Penalties","Zoning Districts, Regulations, and Map","Planned Unit Development (PUD) District","Site Plan Review","Special Land Uses","Zoning Board of Appeals (ZBA)","Zoning Map and Text Amendments","Nonconforming Lots, Structures, and Uses","Off-Street Parking and Loading","Landscaping and Screening","Environmental Protection","Access and Private Roads","Signs","Standards for Specific Land Uses","Supplemental Provisions","Definitions"]'::jsonb, 30, 'published', now())
